package com.micaftic.morpher.core.gui;

import com.micaftic.morpher.YesSteveModel;
import net.minecraft.resources.ResourceLocation;

/**
 * Texture identifiers for the unified animation roulette. Files are
 * generated by {@code tools/gen_roulette_icons.py} and shipped under
 * {@code assets/sparkle_morpher/texture/roulette/}.
 *
 * <p>All icons are white-on-transparent sprites. The roulette tints
 * them at draw time through the {@link RouletteTheme} palette so a
 * single asset works for every visual state.</p>
 */
public final class RouletteIcons {

    private RouletteIcons() {
    }

    public static final ResourceLocation LOCK = id("texture/roulette/lock.png");
    public static final ResourceLocation UNLOCK = id("texture/roulette/unlock.png");
    public static final ResourceLocation SETTINGS = id("texture/roulette/settings.png");
    public static final ResourceLocation ARROW_LEFT = id("texture/roulette/arrow_left.png");
    public static final ResourceLocation ARROW_RIGHT = id("texture/roulette/arrow_right.png");
    public static final ResourceLocation EDIT = id("texture/roulette/edit.png");

    private static ResourceLocation id(String path) {
        return ResourceLocation.fromNamespaceAndPath(YesSteveModel.MOD_ID, path);
    }
}
